import React from 'react';

interface AssetToolbarProps {
  selectedCount: number;
  onAddNew: () => void;
  onDeleteSelected: () => void;
  onClearFilters: () => void;
  onSelectColumns: () => void;
}

const AssetToolbar: React.FC<AssetToolbarProps> = ({
  selectedCount,
  onAddNew,
  onDeleteSelected,
  onClearFilters,
  onSelectColumns,
}) => {
  return (
    <div className="rounded-lg border border-slate-200 bg-white px-5 py-5 shadow-sm">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div className="text-sm text-slate-500">Assets Actions</div>
        <div className="flex flex-wrap items-center gap-3">
          <button
            type="button"
            onClick={onAddNew}
            className="inline-flex items-center gap-2 rounded-md bg-blue-600 px-4 py-2 text-sm font-semibold text-white shadow-sm transition hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <svg className="h-4 w-4" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
              <path d="M8 3V13M3 8H13" stroke="currentColor" strokeWidth="1.8" strokeLinecap="round" />
            </svg>
            Add new
          </button>
          <button
            type="button"
            onClick={onDeleteSelected}
            className="inline-flex items-center gap-2 rounded-md border border-slate-300 bg-white px-4 py-2 text-sm font-semibold text-slate-700 transition hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <svg className="h-4 w-4" viewBox="0 0 16 16" fill="none" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
              <path d="M3 4H13M6 4V3H10V4M5 6V13H11V6" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
            </svg>
            Delete{selectedCount > 0 ? ` (${selectedCount})` : ' (selected)'}
          </button>
        </div>
      </div>

      <div className="mt-4 flex flex-col gap-3 sm:flex-row sm:justify-end">
        <button
          type="button"
          onClick={onClearFilters}
          className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 transition hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          Clear All Filters
        </button>
        <button
          type="button"
          onClick={onSelectColumns}
          className="rounded-md border border-slate-300 bg-white px-4 py-2 text-sm text-slate-700 transition hover:bg-slate-50 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          &#9654; Select Columns
        </button>
      </div>
    </div>
  );
};

export default AssetToolbar;
